package agent

import (
	"bytes"
	"os"
	"path/filepath"
	"strings"
	"testing"
)

// TestPrompts_ClaudeVariant_ByteIdentical is a golden snapshot test that
// verifies executeBeadInstructionsClaudeText (assembled from shared instr*
// blocks) is byte-identical to the captured baseline. Any instruction edit
// must be deliberate — run UPDATE_GOLDEN=1 go test to regenerate.
func TestPrompts_ClaudeVariant_ByteIdentical(t *testing.T) {
	testPromptGolden(t, "claude_variant.golden", executeBeadInstructionsClaudeText)
}

// TestPrompts_AgentVariant_ByteIdentical is a golden snapshot test that
// verifies executeBeadInstructionsAgentText (assembled from shared instr*
// blocks) is byte-identical to the captured baseline. Any instruction edit
// must be deliberate — run UPDATE_GOLDEN=1 go test to regenerate.
func TestPrompts_AgentVariant_ByteIdentical(t *testing.T) {
	testPromptGolden(t, "agent_variant.golden", executeBeadInstructionsAgentText)
}

func testPromptGolden(t *testing.T, name, got string) {
	t.Helper()
	dir := filepath.Join("testdata", "prompts")
	path := filepath.Join(dir, name)
	if os.Getenv("UPDATE_GOLDEN") == "1" {
		if err := os.MkdirAll(dir, 0o755); err != nil {
			t.Fatalf("mkdir: %v", err)
		}
		if err := os.WriteFile(path, []byte(got), 0o644); err != nil {
			t.Fatalf("write golden: %v", err)
		}
		t.Logf("updated golden %s (%d bytes)", path, len(got))
		return
	}
	want, err := os.ReadFile(path)
	if err != nil {
		t.Fatalf("read golden %s: %v (run UPDATE_GOLDEN=1 to generate)", path, err)
	}
	if !bytes.Equal([]byte(got), want) {
		gotLines := strings.Split(got, "\n")
		wantLines := strings.Split(string(want), "\n")
		for i := 0; i < len(gotLines) && i < len(wantLines); i++ {
			if gotLines[i] != wantLines[i] {
				t.Errorf("first diff at line %d:\n  got:  %q\n  want: %q", i+1, gotLines[i], wantLines[i])
				break
			}
		}
		if len(gotLines) != len(wantLines) {
			t.Errorf("line count: got %d, want %d", len(gotLines), len(wantLines))
		}
		t.Fatalf("golden snapshot mismatch for %s (%d bytes got, %d bytes want); run UPDATE_GOLDEN=1 go test to regenerate after intentional changes", name, len(got), len(want))
	}
}

